import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"What Autofac Is","description":"","frontmatter":{},"headers":[],"relativePath":"start/what-is-autofac.md","filePath":"start/what-is-autofac.md","lastUpdated":null}'),s={name:"start/what-is-autofac.md"};function n(i,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="what-autofac-is" tabindex="-1">What Autofac Is <a class="header-anchor" href="#what-autofac-is" aria-label="Permalink to &quot;What Autofac Is&quot;">​</a></h1><p>Autofac is the control plane around autonomous software-delivery agents. It is not a replacement for source control, CI/CD, issue tracking, or human review. It coordinates those systems through governed workflow runs.</p><p>The product thesis is simple: agents can plan, code, test, and open pull requests, but powerful automation needs process boundaries, policy, sandboxing, and evidence.</p><h2 id="the-core-loop" tabindex="-1">The core loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The core loop&quot;">​</a></h2><ol><li>A trigger starts a workflow run. The trigger can be an API call, a GitHub webhook, a scheduled event, or another integration.</li><li>The workflow engine advances through a BPMN model.</li><li>Agent tasks assemble a prompt from the workflow task, agent profile, skills, and run context.</li><li>Model calls and tool calls are limited by budget, permissions, and policy.</li><li>Human approval tasks pause the run until an approver decides.</li><li>Wait states resume from timers or external events.</li><li>The run leaves an evidence pack that can be audited.</li></ol><h2 id="who-uses-it" tabindex="-1">Who uses it <a class="header-anchor" href="#who-uses-it" aria-label="Permalink to &quot;Who uses it&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Typical work</th></tr></thead><tbody><tr><td>Operator</td><td>Starts runs, watches progress, retries or cancels failed runs, handles operational exceptions.</td></tr><tr><td>Approver</td><td>Reviews approval requests, risk rationale, generated output, and evidence before allowing the workflow to continue.</td></tr><tr><td>Workflow designer</td><td>Models delivery processes in BPMN and configures agent tasks, approvals, policies, and triggers.</td></tr><tr><td>Administrator</td><td>Configures identity, model providers, GitHub/Jira/Slack/Teams integrations, storage, runtime, and sandbox settings.</td></tr><tr><td>Developer</td><td>Extends agents, tools, workflow runtime behavior, integrations, and the web UI.</td></tr></tbody></table><h2 id="what-is-open-source" tabindex="-1">What is open source <a class="header-anchor" href="#what-is-open-source" aria-label="Permalink to &quot;What is open source&quot;">​</a></h2><p>The open-source core is intended to run a governed, self-hosted workflow end to end: the BPMN runtime, agent orchestration, Docker sandboxing, GitHub connector, approvals, evidence export, artifact storage, and the web UI. Enterprise features such as SSO/OIDC, fine-grained RBAC, multi-tenant operations, advanced compliance packs, and scale features are commercial-tier capabilities. See <a href="/reference/open-core.html">Open Core Boundary</a>.</p><h2 id="what-to-read-next" tabindex="-1">What to read next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to read next&quot;">​</a></h2><ul><li>New to Autofac: <a href="/start/quickstart.html">Quickstart</a></li><li>Operating the product: <a href="/manual/runs.html">Runs</a></li><li>Designing workflows: <a href="/manual/workflow-authoring.html">Workflow Authoring</a></li><li>Administering the platform: <a href="/admin/deployment.html">Deployment</a></li></ul>',11)])])}const f=t(s,[["render",n]]);export{p as __pageData,f as default};
